class WsSecurityTimestampHandler implements SOAPHandler<SOAPMessageContext> {

    static final String CREATED_PROPERTY = "wssecurity.timestamp.created";
    static final String EXPIRES_PROPERTY = "wssecurity.timestamp.expires";
    private static final String WSSE_NS =
            "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";
    private static final String WSU_NS =
            "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";
    private static final Duration MAX_CLOCK_SKEW = Duration.ofMinutes(2);
    private static final Duration MAX_TTL = Duration.ofMinutes(5);
    private static final Set<String> SEEN_TOKENS = ConcurrentHashMap.newKeySet();

    @Override
    public boolean handleMessage(SOAPMessageContext context) {
        Boolean outbound = (Boolean) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);
        if (Boolean.TRUE.equals(outbound)) {
            return true;
        }

        try {
            SOAPMessage soapMessage = context.getMessage();
            TimestampInfo timestampInfo = extractTimestamp(soapMessage);

            validateTimestamp(timestampInfo);

            context.put(CREATED_PROPERTY, timestampInfo.createdRaw);
            context.setScope(CREATED_PROPERTY, MessageContext.Scope.APPLICATION);
            context.put(EXPIRES_PROPERTY, timestampInfo.expiresRaw);
            context.setScope(EXPIRES_PROPERTY, MessageContext.Scope.APPLICATION);

            return true;
        } catch (ProtocolException e) {
            throw e;
        } catch (Exception e) {
            throw SoapFaultUtil.securityFault("WS-Security timestamp validation failed: " + e.getMessage());
        }
    }

    private TimestampInfo extractTimestamp(SOAPMessage soapMessage) throws Exception {
        SOAPHeader header = soapMessage.getSOAPHeader();
        if (header == null) {
            throw SoapFaultUtil.securityFault("SOAP Header is missing");
        }

        Node securityNode = findFirstChild(header, WSSE_NS, "Security");
        if (securityNode == null) {
            throw SoapFaultUtil.securityFault("WS-Security Security header not found");
        }

        Node timestampNode = findFirstChild(securityNode, WSU_NS, "Timestamp");
        if (timestampNode == null) {
            throw SoapFaultUtil.securityFault("WS-Security Timestamp token not found");
        }

        Node createdNode = findFirstChild(timestampNode, WSU_NS, "Created");
        Node expiresNode = findFirstChild(timestampNode, WSU_NS, "Expires");

        if (createdNode == null || expiresNode == null) {
            throw SoapFaultUtil.securityFault("Timestamp Created/Expires elements are required");
        }

        String created = createdNode.getTextContent() == null ? null : createdNode.getTextContent().trim();
        String expires = expiresNode.getTextContent() == null ? null : expiresNode.getTextContent().trim();

        if (created == null || created.isEmpty() || expires == null || expires.isEmpty()) {
            throw SoapFaultUtil.securityFault("Timestamp Created/Expires values are empty");
        }

        TimestampInfo info = new TimestampInfo();
        info.createdRaw = created;
        info.expiresRaw = expires;
        info.created = Instant.parse(created);
        info.expires = Instant.parse(expires);

        Node idAttr = timestampNode.getAttributes() != null
                ? timestampNode.getAttributes().getNamedItemNS(WSU_NS, "Id")
                : null;
        info.tokenId = idAttr != null ? idAttr.getNodeValue() : created + "|" + expires;

        return info;
    }

    private Node findFirstChild(Node parent, String namespaceUri, String localName) {
        if (parent == null) {
            return null;
        }
        NodeList children = parent.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (localName.equals(child.getLocalName()) && namespaceUri.equals(child.getNamespaceURI())) {
                return child;
            }
            Node nested = findFirstChild(child, namespaceUri, localName);
            if (nested != null) {
                return nested;
            }
        }
        return null;
    }

    private void validateTimestamp(TimestampInfo info) {
        Instant now = Instant.now();

        if (info.expires.isBefore(info.created) || info.expires.equals(info.created)) {
            throw SoapFaultUtil.securityFault("Timestamp Expires must be after Created");
        }

        if (Duration.between(info.created, info.expires).compareTo(MAX_TTL) > 0) {
            throw SoapFaultUtil.securityFault("Timestamp validity window exceeds allowed TTL");
        }

        if (info.created.isAfter(now.plus(MAX_CLOCK_SKEW))) {
            throw SoapFaultUtil.securityFault("Timestamp Created is in the future");
        }

        if (info.expires.isBefore(now.minus(MAX_CLOCK_SKEW))) {
            throw SoapFaultUtil.securityFault("Timestamp has expired");
        }

        if (!SEEN_TOKENS.add(info.tokenId)) {
            throw SoapFaultUtil.securityFault("Replay attack detected: duplicate timestamp token");
        }
    }

    @Override
    public boolean handleFault(SOAPMessageContext context) {
        return true;
    }

    @Override
    public void close(MessageContext context) {
    }

    @Override
    public Set<QName> getHeaders() {
        return Collections.singleton(new QName(WSSE_NS, "Security"));
    }

    static class TimestampInfo {
        String createdRaw;
        String expiresRaw;
        Instant created;
        Instant expires;
        String tokenId;
    }
}

class SoapFaultUtil {

    static ProtocolException clientFault(String message) {
        return buildFault("Client", message);
    }

    static ProtocolException securityFault(String message) {
        return buildFault("wsse:InvalidSecurity", message);
    }

    private static ProtocolException buildFault(String code, String message) {
        try {
            SOAPFactory factory = SOAPFactory.newInstance();
            SOAPFault fault = factory.createFault();
            if (code.contains(":")) {
                fault.setFaultCode(code);
            } else {
                fault.setFaultCode(new QName("http://schemas.xmlsoap.org/soap/envelope/", code));
            }
            fault.setFaultString(message);
            return new ProtocolException(message, new SOAPException(message));
        } catch (Exception e) {
            return new ProtocolException(message, e);
        }
    }
}

